import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"深化研究：算电协同领域公司收入验证","description":"","frontmatter":{},"headers":[],"relativePath":"算电协同/_深化_2026-06-13_算电协同公司收入验证.md","filePath":"算电协同/_深化_2026-06-13_算电协同公司收入验证.md","lastUpdated":1781535932000}'),o={name:"算电协同/_深化_2026-06-13_算电协同公司收入验证.md"};function h(l,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="深化研究-算电协同领域公司收入验证" tabindex="-1">深化研究：算电协同领域公司收入验证 <a class="header-anchor" href="#深化研究-算电协同领域公司收入验证" aria-label="Permalink to &quot;深化研究：算电协同领域公司收入验证&quot;">​</a></h1><p><strong>日期：</strong> 2026-06-13 | <strong>来源：</strong> websearch + 研报 + 公司公告 <strong>对应问题：</strong> 待深化问题 P0#4</p><hr><h2 id="一、核心判断" tabindex="-1">一、核心判断 <a class="header-anchor" href="#一、核心判断" aria-label="Permalink to &quot;一、核心判断&quot;">​</a></h2><p>算电协同领域<strong>已有公司产生真实收入</strong>，但主要集中在<strong>资产持有型</strong>（电站+数据中心）和<strong>技术服务型</strong>（虚拟电厂/需求响应平台），纯&quot;算电协同&quot;作为独立商业模式的公司尚少。</p><hr><h2 id="二、已确认收入的标的" tabindex="-1">二、已确认收入的标的 <a class="header-anchor" href="#二、已确认收入的标的" aria-label="Permalink to &quot;二、已确认收入的标的&quot;">​</a></h2><h3 id="华电新能-600930-——-✅-真实收入-2-7亿-年" tabindex="-1">华电新能（600930）—— ✅ 真实收入 2.7亿/年 <a class="header-anchor" href="#华电新能-600930-——-✅-真实收入-2-7亿-年" aria-label="Permalink to &quot;华电新能（600930）—— ✅ 真实收入 2.7亿/年&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>数据</th></tr></thead><tbody><tr><td>和林格尔风光储直供数据中心</td><td>一期36万千瓦</td></tr><tr><td>年供绿电</td><td>7.6亿度</td></tr><tr><td>项目年收益</td><td><strong>约2.7亿元</strong></td></tr><tr><td>电价溢价</td><td>较传统外送溢价15%-20%</td></tr><tr><td>受益方</td><td>华电新能（发电侧）+ 并行科技等（用电侧）</td></tr></tbody></table><p><strong>收入验证：</strong> 上市公司公告数据，可靠</p><h3 id="并行科技-839493-bj-——-✅-真实成本节省-630万-年" tabindex="-1">并行科技（839493.BJ）—— ✅ 真实成本节省 630万/年 <a class="header-anchor" href="#并行科技-839493-bj-——-✅-真实成本节省-630万-年" aria-label="Permalink to &quot;并行科技（839493.BJ）—— ✅ 真实成本节省 630万/年&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>数据</th></tr></thead><tbody><tr><td>与华电新能合作</td><td>绿电直供</td></tr><tr><td>年节省电费</td><td><strong>630万元</strong>（当前算力规模）</td></tr><tr><td>模式</td><td>算力企业直接受益于低价绿电</td></tr></tbody></table><p><strong>收入验证：</strong> 新三板挂牌公司公开信息</p><h3 id="优刻得-688158-——-✅-乌兰察布智算中心年毛利-1-73亿" tabindex="-1">优刻得（688158）—— ✅ 乌兰察布智算中心年毛利 1.73亿 <a class="header-anchor" href="#优刻得-688158-——-✅-乌兰察布智算中心年毛利-1-73亿" aria-label="Permalink to &quot;优刻得（688158）—— ✅ 乌兰察布智算中心年毛利 1.73亿&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>数据</th></tr></thead><tbody><tr><td>乌兰察布智算中心（2300机柜）</td><td>年收入2.76亿，年毛利<strong>1.73亿元</strong></td></tr><tr><td>毛利率</td><td>62.7%（vs 公司整体18.86%）</td></tr><tr><td>电费节省来源</td><td>绿电占比80%，电价0.25元/度</td></tr></tbody></table><p><strong>收入验证：</strong> 上市公司公告，但前提是机柜达到90%上架率</p><hr><h2 id="三、正在验证-早期阶段的标的" tabindex="-1">三、正在验证/早期阶段的标的 <a class="header-anchor" href="#三、正在验证-早期阶段的标的" aria-label="Permalink to &quot;三、正在验证/早期阶段的标的&quot;">​</a></h2><h3 id="瓦特智能、清大科越等-ai-电力调度" tabindex="-1">瓦特智能、清大科越等（AI+电力调度） <a class="header-anchor" href="#瓦特智能、清大科越等-ai-电力调度" aria-label="Permalink to &quot;瓦特智能、清大科越等（AI+电力调度）&quot;">​</a></h3><ul><li>提供AI Agent进行电力调度优化</li><li>客户案例存在，但<strong>收入规模未公开</strong></li><li>需要验证：合同是试点项目还是量产部署</li></ul><h3 id="数据中心需求响应聚合商" tabindex="-1">数据中心需求响应聚合商 <a class="header-anchor" href="#数据中心需求响应聚合商" aria-label="Permalink to &quot;数据中心需求响应聚合商&quot;">​</a></h3><ul><li>各省虚拟电厂试点项目众多</li><li>但单体项目金额小（百万级），尚未形成可观收入</li><li>内蒙古、山西、广东进展较快</li></ul><hr><h2 id="四、商业模式类型与可投资性评分" tabindex="-1">四、商业模式类型与可投资性评分 <a class="header-anchor" href="#四、商业模式类型与可投资性评分" aria-label="Permalink to &quot;四、商业模式类型与可投资性评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>代表公司</th><th>收入确定性</th><th>可规模化</th><th>PE/VC 时机</th></tr></thead><tbody><tr><td>风光直供数据中心（资产型）</td><td>华电新能</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>已成熟，适合Pre-IPO</td></tr><tr><td>智算中心运营（算力出租）</td><td>优刻得/并行科技</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>高增长，适合成长期</td></tr><tr><td>VPP/需求响应平台（技术型）</td><td>多家创业公司</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>早期，适合天使/A轮</td></tr><tr><td>AI调度优化（SaaS/软件）</td><td>瓦特智能/清大科越</td><td>⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>极早期，需验证PMF</td></tr><tr><td>绿电交易撮合（平台型）</td><td>多家初创</td><td>⭐⭐</td><td>⭐⭐⭐⭐</td><td>极早期</td></tr></tbody></table><hr><h2 id="五、关键信息来源" tabindex="-1">五、关键信息来源 <a class="header-anchor" href="#五、关键信息来源" aria-label="Permalink to &quot;五、关键信息来源&quot;">​</a></h2><ul><li>华电新能（600930）公司公告</li><li>优刻得（688158）年报及公开信息</li><li>并行科技（839493.BJ）公告</li><li>财联社数据中心基建调研（2026-06-03）</li><li>内蒙古&quot;人工智能+&quot;行动方案（2026-04）</li></ul>',28)])])}const c=d(o,[["render",h]]);export{u as __pageData,c as default};
